#nullable enable // autogenerated

using MVZ2.GameContent.Fragments;
using MVZ2.Vanilla.Contraptions;
using MVZ2Logic.Entities;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Buffs.Contraptions
{
    [AutoBuffDefinition(VanillaBuffNames.Contraption.hellfireCursed)]
    public class FireDispenserSoulFireBuff : BuffDefinition
    {
        public FireDispenserSoulFireBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new NamespaceIDModifier(VanillaContraptionProps.FRAGMENT_ID, SetOperator.Set, VanillaFragmentID.hellfireCursed));
            AddModifier(ColorModifier.Override(LogicEntityProps.LIGHT_COLOR, new Color(0, 1, 1)));
        }
    }
}
